import { useSimulationStore } from '../store';

export default function Header() {
  const { balance, isRunning, toggleSimulation } = useSimulationStore();

  const balanceColor = balance >= 10000 ? 'text-[#00ff88]' : 'text-[#ff4d4d]';

  return (
    <header className="flex items-center justify-between px-6 py-4 bg-[#161b22]/80 backdrop-blur-md border-b border-white/10">
      <div className="flex items-center gap-3">
        <span className="text-xl font-bold tracking-widest text-white uppercase">
          Algo<span className="text-[#00ff88]">-Crafter</span>
        </span>
      </div>

      <div className="flex items-center gap-6">
        <div className="text-right">
          <p className="text-xs text-white/40 uppercase tracking-widest">Balance</p>
          <p className={`font-mono text-lg font-semibold ${balanceColor}`}>
            {balance.toLocaleString('en-US', { style: 'currency', currency: 'USD' })}
          </p>
        </div>

        <button
          onClick={toggleSimulation}
          className={`px-5 py-2 rounded-lg font-semibold text-sm tracking-wide transition-all duration-200 border ${
            isRunning
              ? 'bg-[#ff4d4d]/10 border-[#ff4d4d]/50 text-[#ff4d4d] hover:bg-[#ff4d4d]/20'
              : 'bg-[#00ff88]/10 border-[#00ff88]/50 text-[#00ff88] hover:bg-[#00ff88]/20'
          }`}
        >
          {isRunning ? '⏹ Stop' : '▶ Start'}
        </button>
      </div>
    </header>
  );
}
